import tarfile
import os
from pathlib import Path

def extract_tar(tar_path, destination):
    tar_path = Path(tar_path).resolve()
    destination = Path(destination).resolve()
    
    if not tar_path.is_file():
        raise ValueError("Tar file does not exist")
    
    if not destination.is_dir():
        destination.mkdir(parents=True, exist_ok=True)
    
    with tarfile.open(tar_path, 'r') as tar:
        members = []
        for member in tar.getmembers():
            if os.path.isabs(member.name):
                raise ValueError("Tar file contains absolute paths")
            if member.name.startswith('../'):
                raise ValueError("Tar file contains paths outside destination")
            if member.name.startswith('/'):
                raise ValueError("Tar file contains absolute paths")
            members.append(member)
        
        tar.extractall(path=destination, members=members)